// NFA ACCEPT(string w)
// Q: set of states, Σ: alphabet, δ: transition function
// q0: initial state, F: final states

function accept(NFA, w):
 current_states = ε-closure({q0}) // Initial set with ε-closure

 for each symbol a in w:
 next_states = empty set
 for each state s in current_states:
 next_states = next_states ∪ δ(s, a)
 current_states = ε-closure(next_states)

 // Check if any final state is in current set
 for each state f in F:
 if f ∈ current_states:
 return ACCEPT

 return REJECT

// POWERSET CONSTRUCTION
// Input: NFA = (Q, Σ, δ, q0, F)
// Output: DFA = (Q', Σ, δ', q0', F')

function powerset_construction(NFA):
 Q' = empty set
 δ' = empty function

 // Initial DFA state
 q0' = epsilon_closure({q0})
 Q' = {q0'}
 worklist = [q0']

 while worklist is not empty:
 current = worklist.pop()

 for each symbol a in Σ:
 // Compute next state set
 next_set = empty set
 for each state s in current:
 next_set = next_set ∪ δ(s, a)

 new_state = epsilon_closure(next_set)

 // Add to DFA if new
 if new_state ∉ Q':
 Q' = Q' ∪ {new_state}
 worklist.append(new_state)

 δ'(current, a) = new_state

 // Final states: sets containing any NFA final state
 F' = {S | S ∈ Q' and S ∩ F ≠ ∅}

 return DFA = (Q', Σ, δ', q0', F')

// EPSILON CLOSURE
// Returns all states reachable via zero or more ε-transitions

function epsilon_closure(S):
 // S is a set of states
 closure = S // Start with all states in S
 stack = list(S)

 while stack is not empty:
 state = stack.pop()

 // Get states reachable via one ε-transition
 epsilon_reachable = δ(state, ε)

 for each t in epsilon_reachable:
 if t ∉ closure:
 closure.add(t)
 stack.push(t)

 return closure
